// ---- 所有类别模板汇总 ----
const ALL_TEMPLATES = [
  { catId: 1, templates: AI_NEWS },
  { catId: 2, templates: CLOUD_TEMPLATES },
  { catId: 3, templates: CHIP_TEMPLATES },
  { catId: 4, templates: DEV_TOOLS },
  { catId: 5, templates: AI_APPS },
  { catId: 6, templates: TECH_TRENDS },
]

// ---- AI配图描述 ----
const COVER_DESCRIPTIONS = [
  'A futuristic technology news studio with holographic AI interfaces, blue and purple neon lighting, floating data particles, 8K resolution, cinematic lighting',
  'Abstract digital brain made of glowing circuit pathways, deep blue background with golden connection points, technological aesthetic, high detail',
  'Futuristic data center corridor with blue LED lighting, rows of servers with blinking lights, misty atmosphere, wide angle perspective, cyberpunk style',
  'Glowing GPU chip with rainbow reflection on dark surface, intricate circuit details visible, macro photography, dramatic lighting, technology magazine style',
  'Abstract network visualization with connected nodes and flowing data streams, dark background with vibrant blue and orange particles, sci-fi aesthetic',
  'Futuristic city skyline with holographic digital overlays, neon lights reflecting on wet streets, flying vehicles in distance, cyberpunk atmosphere, cinematic',
  'Human hand touching a holographic AI interface with glowing blue particles spreading from contact point, dramatic lighting, high contrast, minimalist composition',
  'Abstract visualization of neural network firing with bright blue and purple synaptic connections against dark background, organic and technological fusion',
  'Futuristic workspace with multiple transparent holographic screens displaying code and data visualization, warm ambient lighting, sleek minimal design',
  'Glowing quantum processor with intricate golden circuits on dark silicon wafer, macro detail shot, bokeh background with blue light particles',
  'Digital DNA helix made of binary code and glowing data streams against deep space background, biotech meets computing aesthetic, high detail',
  'Futuristic robot hand reaching out from darkness with detailed mechanical joints and glowing blue energy lines, dramatic side lighting, cinematic composition',
]

function randomDate(daysBack = 7) {
  const now = Date.now()
  const offset = Math.floor(Math.random() * daysBack * 24 * 60 * 60 * 1000)
  return new Date(now - offset).toISOString()
}

function pickRandom(arr) {
  return arr[Math.floor(Math.random() * arr.length)]
}

function generateCoverDescription(title) {
  const baseDesc = pickRandom(COVER_DESCRIPTIONS)
  return `${title} - ${baseDesc}`
}

async function main() {
  console.log('========================================')
  console.log('  批量生成 120 条科技虚拟新闻素材')
  console.log('========================================\n')

  const db = await initDatabase()

  // 防止重复生成：如果已有足够文章则跳过
  const articleCount = db.prepare('SELECT COUNT(*) as cnt FROM articles').get()
  if (articleCount && articleCount.cnt >= 120) {
    console.log(`  ⚠️ 数据库中已有 ${articleCount.cnt} 篇文章，跳过种子数据生成\n`)
    return
  }

  // 1. 确保第6个分类存在
  const existing = db.prepare('SELECT id FROM categories WHERE slug = ?').get('ai-applications')
  if (!existing) {
    db.prepare("INSERT INTO categories (name, slug, description, sort_order) VALUES (?, ?, ?, ?)")
      .run('AI行业应用', 'ai-applications', 'AI技术在医疗、教育、金融等行业的实际应用案例和解决方案', 5)
    // 更新后续分类的排序
    db.prepare("UPDATE categories SET sort_order = 6 WHERE slug = 'tech-trends'").run()
    db.save()
    console.log('  ✅ 已添加分类: AI行业应用\n')
  } else {
    console.log('  ℹ️ 分类 AI行业应用 已存在\n')
  }

  let totalInserted = 0

  for (const group of ALL_TEMPLATES) {
    const cat = CATEGORIES.find(c => c.id === group.catId)
    console.log(`  📁 [${cat.name}] (${cat.slug}) - 生成 ${group.templates.length} 条`)

    for (let i = 0; i < group.templates.length; i++) {
      const t = group.templates[i]
      const publishedAt = randomDate(30)
      const createdAt = publishedAt
      const catCovers = { 1: 'ai2026', 2: 'cloud2026', 3: 'chip2026', 4: 'devtool2026', 5: 'aiapp2026', 6: 'tech2026' }
      const coverUrl = `https://picsum.photos/seed/${catCovers[group.catId] || 'tech'}/800/400`

      // 插入文章
      const likes = Math.floor(Math.random() * 5000) + 100
      const comments = Math.floor(Math.random() * 300) + 10
      const result = db.prepare(`
        INSERT INTO articles (title, summary, content, cover_url, source_name, source_url, category_id, status, is_featured, like_count, comment_count, published_at, created_at, updated_at)
        VALUES (?, ?, ?, ?, ?, ?, ?, 'published', ?, ?, ?, ?, ?, ?)
      `).run(
        t.title,
        t.summary,
        t.content,
        coverUrl,
        pickRandom(['TechAI 编辑部', 'AI 科技观察', '前沿科技日报', '智能产业周刊', '未来科技速递']),
        '',
        group.catId,
        Math.random() < 0.15 ? 1 : 0,
        likes, comments,
        publishedAt, createdAt, createdAt
      )

      const articleId = result.lastInsertRowid

      // 处理标签
      if (t.tags && t.tags.length > 0) {
        for (const tagName of t.tags) {
          const slug = tagName.toLowerCase().replace(/\s+/g, '-').replace(/[^\w一-龥-]/g, '')
          db.prepare('INSERT OR IGNORE INTO tags (name, slug) VALUES (?, ?)').run(tagName, slug)
          const tag = db.prepare('SELECT id FROM tags WHERE slug = ?').get(slug)
          if (tag) {
            db.prepare('INSERT OR IGNORE INTO article_tags (article_id, tag_id) VALUES (?, ?)').run(articleId, tag.id)
          }
        }
      }

      totalInserted++
    }
  }

  db.save()

  console.log(`\n========================================`)
  console.log(`  ✅ 共生成 ${totalInserted} 条虚拟新闻`)
  console.log(`  📊 各分类分布:`)

  for (const cat of CATEGORIES) {
    const count = db.prepare('SELECT COUNT(*) as c FROM articles WHERE category_id = ?').get(cat.id)
    console.log(`     ${cat.name}: ${count.c} 条`)
  }

  const total = db.prepare('SELECT COUNT(*) as c FROM articles').get()
  console.log(`  📈 数据库文章总计: ${total.c} 条`)
  console.log(`========================================\n`)

  // 输出示例
  console.log('📋 部分文章预览:\n')
  const samples = db.prepare(`
    SELECT a.id, a.title, c.name as category, a.created_at
    FROM articles a
    LEFT JOIN categories c ON a.category_id = c.id
    ORDER BY a.id DESC
    LIMIT 10
  `).all()

  for (const s of samples.reverse()) {
    console.log(`  #${s.id} [${s.category}] ${s.title}`)
  }

  console.log(`\n✅ 完成！请在后台管理面板中查看所有文章。`)

  db.save()
  process.exit(0)
}

main().catch(err => {
  console.error('❌ 脚本执行出错:', err)
  process.exit(1)
})
